import React, { useEffect, useState } from 'react';
import { tokensApi } from '../services/api';

const Tokens = () => {
  const [tokens, setTokens] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [selectedNetwork, setSelectedNetwork] = useState('all');

  useEffect(() => {
    const fetchTokens = async () => {
      try {
        setLoading(true);
        let response;

        if (selectedNetwork === 'all') {
          response = await tokensApi.getAllTokens();
        } else {
          response = await tokensApi.getTokensByNetwork(selectedNetwork);
        }

        setTokens(response.data);
        setError('');
      } catch (error) {
        console.error('Ошибка при получении токенов:', error);
        setError('Не удалось загрузить список токенов');
      } finally {
        setLoading(false);
      }
    };

    fetchTokens();
  }, [selectedNetwork]);

  const getNetworkName = (networkId) => {
    switch (networkId) {
      case 1:
        return 'Ethereum';
      case 3:
        return 'TON';
      default:
        return `Сеть #${networkId}`;
    }
  };

  return (
    <div className="container">
      <h2>Доступные токены</h2>

      {error && <div className="alert alert-danger">{error}</div>}

      <div className="card">
        <div style={{ marginBottom: '20px' }}>
          <label htmlFor="network-filter" className="form-label">
            Фильтр по сети:
          </label>
          <select
            id="network-filter"
            className="form-control"
            value={selectedNetwork}
            onChange={(e) => setSelectedNetwork(e.target.value)}
            style={{ maxWidth: '300px' }}
          >
            <option value="all">Все сети</option>
            <option value="1">Ethereum</option>
            <option value="3">TON</option>
          </select>
        </div>

        {loading ? (
          <p>Загрузка токенов...</p>
        ) : tokens.length > 0 ? (
          <div style={{ overflowX: 'auto' }}>
            <table style={{ width: '100%', borderCollapse: 'collapse' }}>
              <thead>
                <tr>
                  <th style={{ textAlign: 'left', padding: '10px', borderBottom: '1px solid #ddd' }}>ID</th>
                  <th style={{ textAlign: 'left', padding: '10px', borderBottom: '1px solid #ddd' }}>Название</th>
                  <th style={{ textAlign: 'left', padding: '10px', borderBottom: '1px solid #ddd' }}>Символ</th>
                  <th style={{ textAlign: 'left', padding: '10px', borderBottom: '1px solid #ddd' }}>Сеть</th>
                  <th style={{ textAlign: 'center', padding: '10px', borderBottom: '1px solid #ddd' }}>Доступен для стейкинга</th>
                  <th style={{ textAlign: 'right', padding: '10px', borderBottom: '1px solid #ddd' }}>Действия</th>
                </tr>
              </thead>
              <tbody>
                {tokens.map((token) => (
                  <tr key={token.token_id}>
                    <td style={{ textAlign: 'left', padding: '10px', borderBottom: '1px solid #ddd' }}>{token.token_id}</td>
                    <td style={{ textAlign: 'left', padding: '10px', borderBottom: '1px solid #ddd' }}>{token.token_name}</td>
                    <td style={{ textAlign: 'left', padding: '10px', borderBottom: '1px solid #ddd' }}>{token.token_symbol}</td>
                    <td style={{ textAlign: 'left', padding: '10px', borderBottom: '1px solid #ddd' }}>
                      {getNetworkName(token.token_network_id)}
                    </td>
                    <td style={{ textAlign: 'center', padding: '10px', borderBottom: '1px solid #ddd' }}>
                      {token.staking_available ? '✅' : '❌'}
                    </td>
                    <td style={{ textAlign: 'right', padding: '10px', borderBottom: '1px solid #ddd' }}>
                      {token.staking_available ? (
                        <a href={`/staking/new?token=${token.token_id}`} className="btn" style={{ padding: '5px 10px', fontSize: '14px' }}>
                          Стейкинг
                        </a>
                      ) : (
                        <button className="btn btn-secondary" style={{ padding: '5px 10px', fontSize: '14px' }} disabled>
                          Стейкинг недоступен
                        </button>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <p>Токены не найдены</p>
        )}
      </div>
    </div>
  );
};

export default Tokens;
